external_knowledge:
- "recent past" refers to the year 2022;
- "sales added up to more than a million dollars" means the total sales price is greater than $1,000,000;
- "different buyers" refers to unique buyers, meaning the same buyer purchasing multiple times is counted once.

sql:
SELECT COUNT(*) AS total_properties
FROM properties
WHERE bedrooms > 3;

external_knowledge:
- "seashells" metaphorically refers to properties;
- "resting on the shores" metaphorically refers to being located in Seattle;
- "ocean" metaphorically represents the market;
- "untouched by the waves" metaphorically means no offers were made on the properties;
- "recent year" refers to the last year.

sql:
SELECT MAX(avg_sale_price) AS highest_average_sale_price
FROM (
    SELECT property_id, AVG(sale_price) AS avg_sale_price
    FROM sales
    GROUP BY property_id
) AS property_avg_prices;
